CREATE TRIGGER [dbo].[Defect_History]ON [dbo].[Defect]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.DefectId IS NOT NULL AND d.DefectId IS NULL THEN 'I' 		WHEN i.DefectId IS NOT NULL AND d.DefectId IS NOT NULL THEN 'U' 		WHEN i.DefectId IS NULL AND d.DefectId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.DefectId = d.DefectId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_Defect([DefectId], [DefectCategoryId], [Name], [Description], [IsActive], [IsReworkable], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [DefectId], [DefectCategoryId], [Name], [Description], [IsActive], [IsReworkable], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_Defect([DefectId], [DefectCategoryId], [Name], [Description], [IsActive], [IsReworkable], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [DefectId], [DefectCategoryId], [Name], [Description], [IsActive], [IsReworkable], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND